import os, json
from supabase import create_client

url = os.environ.get('SUPABASE_URL')
key = os.environ.get('SUPABASE_SERVICE_KEY')
sb = create_client(url, key)

# Get all position mastery records with proper cluster_family fields
resp = sb.table('sai_memory').select('content').eq('category', 'position_mastery').execute()

clusters = {'Marketing & Advertising': [], 'Content & Communications': [], 'Legal & Compliance': [], 'Sales & Revenue': []}
for r in resp.data:
    try:
        c = json.loads(r['content']) if isinstance(r['content'], str) else r['content']
        cf = c.get('cluster_family', '')
        cn = c.get('cluster_name', '')
        pn = c.get('position_name', '')
        for fam in clusters:
            if fam in cf:
                clusters[fam].append(f'{cn} > {pn}')
    except:
        pass

for fam, positions in sorted(clusters.items()):
    print(f'\n=== {fam} ({len(positions)} positions) ===')
    for p in sorted(positions):
        print(f'  {p}')
"
